+    #[test]
+    fn ir_edge_kinds_are_distinct() {
+        let kinds = [
+            IrEdgeKind::Generic,
+            IrEdgeKind::Relationship,
+            IrEdgeKind::Message,
+            IrEdgeKind::Timeline,
+            IrEdgeKind::Dependency,
+            IrEdgeKind::Commit,
+        ];
+        for (i, a) in kinds.iter().enumerate() {
+            for (j, b) in kinds.iter().enumerate() {
+                if i == j {
+                    assert_eq!(a, b);
+                } else {
+                    assert_ne!(a, b);
+                }
+            }
+        }
+    }
